interface ListingsTableProps {
  filters: any
}

export function ListingsTable({ filters }: ListingsTableProps) {
  const [sortColumn, setSortColumn] = useState<string | null>("title")
  const [sortDirection, setSortDirection] = useState<"asc" | "desc">("asc")
  const [selectedRows, setSelectedRows] = useState<number[]>([])

  const handleDuplicateListing = (listingId: number) => {
    console.log("Duplicating listing:", listingId)
    // In a real app, you would duplicate the listing
  }

  const handleViewInsights = (listingId: number) => {
    console.log("Viewing insights for listing:", listingId)
    // In a real app, you would show analytics for the listing
  }

  const handleBulkExport = () => {
    console.log("Exporting selected listings:", selectedRows)
    // In a real app, you would export the selected listings
  }

  const handleSort = (column: string) => {
    if (sortColumn === column) {
      setSortDirection(sortDirection === "asc" ? "desc" : "asc")
    } else {
      setSortColumn(column)
      setSortDirection("asc")
    }
  }

  const toggleSelectAll = () => {
    if (selectedRows.length === listings.length) {
      setSelectedRows([])
    } else {
      setSelectedRows(listings.map((listing) => listing.id))
    }
  }

  const toggleSelectRow = (id: number) => {
    if (selectedRows.includes(id)) {
      setSelectedRows(selectedRows.filter((rowId) => rowId !== id))
    } else {
      setSelectedRows([...selectedRows, id])
    }
  }

  // Apply sorting
  const sortedListings = [...listings].sort((a, b) => {
    if (!sortColumn) return 0

    const aValue = a[sortColumn as keyof typeof a]
    const bValue = b[sortColumn as keyof typeof b]

    if (aValue < bValue) return sortDirection === "asc" ? -1 : 1
    if (aValue > bValue) return sortDirection === "asc" ? 1 : -1
    return 0
  })

  // In a real app, you would apply filters here
  const filteredListings = sortedListings

  return (
    <div className="rounded-md border">
      {selectedRows.length > 0 && (
        <div className="flex items-center gap-2 p-4 bg-blue-50 border-b">
          <span className="text-sm text-blue-700">{selectedRows.length} selected</span>
          <Button variant="outline" size="sm" onClick={handleBulkExport}>
            <DownloadIcon className="h-4 w-4 mr-1" />
            Export
          </Button>
          <Button variant="outline" size="sm">
            Bulk Edit
          </Button>
          <Button variant="outline" size="sm">
            Change Status
          </Button>
        </div>
      )}
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead className="w-12">
              <Checkbox checked={selectedRows.length === listings.length} onCheckedChange={toggleSelectAll} />
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("title")}>
              <div className="flex items-center gap-1">
                Title
                {sortColumn === "title" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("type")}>
              <div className="flex items-center gap-1">
                Type
                {sortColumn === "type" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("location")}>
              <div className="flex items-center gap-1">
                Location
                {sortColumn === "location" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("price")}>
              <div className="flex items-center gap-1">
                Price
                {sortColumn === "price" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="cursor-pointer" onClick={() => handleSort("status")}>
              <div className="flex items-center gap-1">
                Status
                {sortColumn === "status" &&
                  (sortDirection === "asc" ? (
                    <ArrowUpIcon className="h-4 w-4" />
                  ) : (
                    <ArrowDownIcon className="h-4 w-4" />
                  ))}
              </div>
            </TableHead>
            <TableHead className="w-24">Actions</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {filteredListings.map((listing) => (
            <TableRow key={listing.id} className={selectedRows.includes(listing.id) ? "bg-muted/50" : ""}>
              <TableCell>
                <Checkbox
                  checked={selectedRows.includes(listing.id)}
                  onCheckedChange={() => toggleSelectRow(listing.id)}
                />
              </TableCell>
              <TableCell className="font-medium">{listing.title}</TableCell>
              <TableCell>{listing.type}</TableCell>
              <TableCell>{listing.location}</TableCell>
              <TableCell>{listing.price}</TableCell>
              <TableCell>
                <Badge
                  variant="outline"
                  className={
                    listing.status === "Active"
                      ? "bg-green-100 text-green-800 hover:bg-green-100 border-green-200"
                      : listing.status === "Pending"
                        ? "bg-yellow-100 text-yellow-800 hover:bg-yellow-100 border-yellow-200"
                        : "bg-gray-100 text-gray-800 hover:bg-gray-100 border-gray-200"
                  }
                >
                  {listing.status}
                </Badge>
              </TableCell>
              <TableCell>
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <Button variant="ghost" size="icon" className="h-8 w-8">
                      <MoreHorizontalIcon className="h-4 w-4" />
                      <span className="sr-only">Open menu</span>
                    </Button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent align="end">
                    <DropdownMenuItem className="flex items-center gap-2">
                      <EyeIcon className="h-4 w-4" />
                      View
                    </DropdownMenuItem>
                    <DropdownMenuItem className="flex items-center gap-2">
                      <PencilIcon className="h-4 w-4" />
                      Edit
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      className="flex items-center gap-2"
                      onClick={() => handleDuplicateListing(listing.id)}
                    >
                      <CopyIcon className="h-4 w-4" />
                      Duplicate
                    </DropdownMenuItem>
                    <DropdownMenuItem
                      className="flex items-center gap-2"
                      onClick={() => handleViewInsights(listing.id)}
                    >
                      <TrendingUpIcon className="h-4 w-4" />
                      View Insights
                    </DropdownMenuItem>
                    <DropdownMenuSeparator />
                    <DropdownMenuItem className="flex items-center gap-2 text-red-600">
                      <TrashIcon className="h-4 w-4" />
                      Delete
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  )
}
